        "s": "<svg width=\"560\" height=\"240\" viewBox=\"0 0 280 120\" style=\"display:block;margin:8px auto;border-radius:8px;background:#f9f9f9\"><rect x=\"2\" y=\"2\" width=\"276\" height=\"13\" fill=\"#3498db\" rx=\"3\"/><text x=\"140\" y=\"11.5\" font-size=\"7\" fill=\"white\" font-weight=\"bold\" text-anchor=\"middle\">The KEY changes what each picture is worth</text><text x=\"26\" y=\"24\" font-size=\"6\" fill=\"#666\" font-weight=\"bold\" text-anchor=\"middle\">KEY</text><text x=\"115\" y=\"24\" font-size=\"6\" fill=\"#666\" font-weight=\"bold\" text-anchor=\"middle\">Same 3 Pictures</text><text x=\"225\" y=\"24\" font-size=\"6\" fill=\"#666\" font-weight=\"bold\" text-anchor=\"middle\">Total</text><line x1=\"2\" y1=\"27\" x2=\"278\" y2=\"27\" stroke=\"#bbb\" stroke-width=\"0.5\"/><rect x=\"2\" y=\"28\" width=\"276\" height=\"24\" fill=\"#d4edda\" rx=\"2\"/><text x=\"26\" y=\"43\" font-size=\"7.5\" fill=\"#155724\" font-weight=\"bold\" text-anchor=\"middle\">📖 = 1</text><text x=\"115\" y=\"45\" font-size=\"11\" text-anchor=\"middle\">📖📖📖</text><text x=\"225\" y=\"43\" font-size=\"8.5\" fill=\"#155724\" font-weight=\"bold\" text-anchor=\"middle\">= 3</text><rect x=\"2\" y=\"55\" width=\"276\" height=\"24\" fill=\"#fff3cd\" rx=\"2\"/><text x=\"26\" y=\"70\" font-size=\"7.5\" fill=\"#856404\" font-weight=\"bold\" text-anchor=\"middle\">📖 = 2</text><text x=\"115\" y=\"72\" font-size=\"11\" text-anchor=\"middle\">📖📖📖</text><text x=\"225\" y=\"70\" font-size=\"8.5\" fill=\"#856404\" font-weight=\"bold\" text-anchor=\"middle\">= 6</text><rect x=\"2\" y=\"82\" width=\"276\" height=\"24\" fill=\"#f8d7da\" rx=\"2\"/><text x=\"26\" y=\"97\" font-size=\"7.5\" fill=\"#721c24\" font-weight=\"bold\" text-anchor=\"middle\">📖 = 5</text><text x=\"115\" y=\"99\" font-size=\"11\" text-anchor=\"middle\">📖📖📖</text><text x=\"225\" y=\"97\" font-size=\"8.5\" fill=\"#721c24\" font-weight=\"bold\" text-anchor=\"middle\">= 15!</text><line x1=\"52\" y1=\"27\" x2=\"52\" y2=\"106\" stroke=\"#bbb\" stroke-width=\"0.5\"/><line x1=\"178\" y1=\"27\" x2=\"178\" y2=\"106\" stroke=\"#bbb\" stroke-width=\"0.5\"/><rect x=\"2\" y=\"109\" width=\"276\" height=\"11\" fill=\"#fff3cd\" rx=\"2\"/><text x=\"140\" y=\"117\" font-size=\"6.5\" fill=\"#856404\" font-weight=\"bold\" text-anchor=\"middle\">Change the KEY → change the TOTAL! Same pictures, different answers.</text></svg>",
